def tail_prob(weights,p,ge=True):
    n=len(weights); q=1-p
    total=0.0
    for mask in range(1<<n):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i &1:
                s+=w; k+=1
        if s >= p-1e-12:
            total += (p**k)*(q**(n-k))
    return total

