def ug_value(bs,p):
    B=sum(bs); T=p*(B+1); lam=p/(1-p)
    h=l=0.0
    n=len(bs); q=1-p
    for mask in range(1<<n):
        s=0; k=0
        for i,b in enumerate(bs):
            if mask>>i &1:
                s+=b; k+=1
        prob=p**k*q**(n-k)
        if s>=T-1e-12: h+=prob
        if s<T-1-1e-12: l+=prob
    return h-lam*l,h,l,T
